-- +goose Up
-- Consolidated green-field schema. Squash of migrations 00001..00008
-- (no deployed instances to migrate). Generated by applying those 8
-- migrations to a clean Postgres 16 and dumping the result, then
-- verified byte-identical to that schema. Plain DDL only -- no goose
-- StatementBegin needed (matches the prior 00001 convention).

CREATE TABLE account_email_change_otps (
    id uuid NOT NULL,
    account_id uuid NOT NULL,
    new_email text NOT NULL,
    code_hash text NOT NULL,
    attempts integer DEFAULT 0 NOT NULL,
    expires_at timestamp with time zone NOT NULL,
    used_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);

CREATE TABLE account_email_otps (
    id uuid NOT NULL,
    account_id uuid NOT NULL,
    code_hash text NOT NULL,
    attempts integer DEFAULT 0 NOT NULL,
    expires_at timestamp with time zone NOT NULL,
    used_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);

CREATE TABLE account_password_reset_otps (
    id uuid NOT NULL,
    account_id uuid NOT NULL,
    code_hash text NOT NULL,
    attempts integer DEFAULT 0 NOT NULL,
    expires_at timestamp with time zone NOT NULL,
    used_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);

CREATE TABLE accounts (
    id uuid NOT NULL,
    email text NOT NULL,
    name text NOT NULL,
    validated_at timestamp with time zone,
    password_hash text,
    password_set_at timestamp with time zone,
    language character varying(10) DEFAULT 'en'::character varying,
    locked_until timestamp with time zone,
    totp_secret_encrypted bytea,
    totp_enabled_at timestamp with time zone,
    totp_backup_codes_encrypted bytea,
    last_totp_step bigint DEFAULT 0 NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);

CREATE TABLE api_keys (
    id uuid NOT NULL,
    workspace_id uuid NOT NULL,
    app_id uuid,
    name text NOT NULL,
    prefix text NOT NULL,
    hash text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    created_by uuid NOT NULL
);

CREATE TABLE app_cors_origins (
    id uuid NOT NULL,
    app_id uuid NOT NULL,
    origin text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);

CREATE TABLE app_ip_allowlist (
    id uuid NOT NULL,
    app_id uuid NOT NULL,
    ip_range text NOT NULL,
    description text,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);

CREATE TABLE app_users (
    app_id uuid NOT NULL,
    user_id uuid NOT NULL,
    status text DEFAULT 'active'::text NOT NULL,
    source character varying(20) NOT NULL,
    joined_at timestamp with time zone DEFAULT now() NOT NULL,
    last_login_at timestamp with time zone,
    CONSTRAINT app_users_status_check CHECK ((status = ANY (ARRAY['active'::text, 'pending'::text, 'disabled'::text])))
);

CREATE TABLE apps (
    id uuid NOT NULL,
    workspace_id uuid NOT NULL,
    product_id uuid NOT NULL,
    type text NOT NULL,
    description text,
    enabled boolean DEFAULT false NOT NULL,
    allow_registration boolean DEFAULT false NOT NULL,
    default_role_id uuid,
    allowed_email_domains text[] DEFAULT '{}'::text[],
    primary_auth_method text DEFAULT 'password'::text NOT NULL,
    auth_method_google boolean DEFAULT true NOT NULL,
    google_oauth_client_id text,
    google_oauth_client_secret_encrypted bytea,
    auth_method_apple boolean DEFAULT false NOT NULL,
    apple_services_id text,
    apple_team_id text,
    apple_key_id text,
    apple_private_key_encrypted bytea,
    auth_method_microsoft boolean DEFAULT false NOT NULL,
    microsoft_client_id text,
    microsoft_client_secret_encrypted bytea,
    microsoft_tenant text DEFAULT 'common'::text NOT NULL,
    auth_method_github boolean DEFAULT false NOT NULL,
    github_client_id text,
    github_client_secret_encrypted bytea,
    webauthn_rpid text,
    require_2fa boolean DEFAULT false NOT NULL,
    allow_account_deletion boolean DEFAULT true NOT NULL,
    allow_email_change boolean DEFAULT false NOT NULL,
    password_min_length integer DEFAULT 8 NOT NULL,
    password_min_zxcvbn_score integer DEFAULT 2 NOT NULL,
    app_url text,
    session_ttl_minutes integer,
    idle_timeout_minutes integer,
    remember_me_ttl_minutes integer,
    access_token_ttl_minutes integer,
    max_sessions_per_user integer,
    cookie_domain text,
    transport_mode text DEFAULT 'local'::text NOT NULL,
    session_cookie_samesite text DEFAULT 'lax'::text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    auth_domain text,
    user_pool_id uuid NOT NULL,
    CONSTRAINT apps_password_min_length_check CHECK (((password_min_length >= 1) AND (password_min_length <= 256))),
    CONSTRAINT apps_password_min_zxcvbn_score_check CHECK (((password_min_zxcvbn_score >= 0) AND (password_min_zxcvbn_score <= 4))),
    CONSTRAINT apps_primary_auth_method_check CHECK ((primary_auth_method = ANY (ARRAY['password'::text, 'code'::text, 'magicLink'::text, 'none'::text]))),
    CONSTRAINT apps_session_cookie_samesite_check CHECK ((session_cookie_samesite = ANY (ARRAY['lax'::text, 'strict'::text]))),
    CONSTRAINT apps_transport_mode_check CHECK ((transport_mode = ANY (ARRAY['local'::text, 'cookie'::text]))),
    CONSTRAINT apps_type_check CHECK ((type = ANY (ARRAY['prod'::text, 'staging'::text, 'dev'::text])))
);

CREATE TABLE attempts (
    id uuid NOT NULL,
    purpose text NOT NULL,
    subject text NOT NULL,
    ip text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);

CREATE TABLE auth_logs (
    id uuid NOT NULL,
    workspace_id uuid NOT NULL,
    app_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    event text NOT NULL,
    method text,
    outcome text NOT NULL,
    failure_reason text,
    subject_user_id uuid,
    subject_account_id uuid,
    email_attempted text,
    actor_type text NOT NULL,
    actor_account_id uuid,
    actor_api_key_id uuid,
    actor_label text,
    ip inet,
    user_agent text,
    session_id uuid,
    request_id text,
    metadata jsonb,
    CONSTRAINT auth_logs_actor_type_check CHECK ((actor_type = ANY (ARRAY['self'::text, 'admin'::text, 'api_key'::text, 'system'::text]))),
    CONSTRAINT auth_logs_outcome_check CHECK ((outcome = ANY (ARRAY['success'::text, 'failed'::text])))
);

CREATE TABLE client_otp_codes (
    id uuid NOT NULL,
    app_id uuid NOT NULL,
    email_norm text NOT NULL,
    code_hash text NOT NULL,
    requested_ip text DEFAULT ''::text NOT NULL,
    requested_user_agent text DEFAULT ''::text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    expires_at timestamp with time zone NOT NULL,
    used_at timestamp with time zone,
    attempts integer DEFAULT 0 NOT NULL,
    last_attempt_at timestamp with time zone,
    CONSTRAINT client_otp_codes_attempts_nonneg CHECK ((attempts >= 0)),
    CONSTRAINT client_otp_codes_expires_after_create CHECK ((expires_at > created_at))
);

CREATE TABLE client_refresh_tokens (
    id uuid NOT NULL,
    session_id uuid NOT NULL,
    token_hash text NOT NULL,
    dpop_jkt text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    expires_at timestamp with time zone NOT NULL,
    rotated_at timestamp with time zone,
    revoked_at timestamp with time zone,
    replaced_by_id uuid,
    user_agent text DEFAULT ''::text NOT NULL,
    ip text DEFAULT ''::text NOT NULL,
    CONSTRAINT client_refresh_tokens_expires_after_create CHECK ((expires_at > created_at))
);

CREATE TABLE client_sessions (
    id uuid NOT NULL,
    user_id uuid NOT NULL,
    app_id uuid,
    remember_me boolean DEFAULT false NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    expires_at timestamp with time zone NOT NULL,
    last_seen_at timestamp with time zone DEFAULT now() NOT NULL,
    user_agent text DEFAULT ''::text NOT NULL,
    ip text DEFAULT ''::text NOT NULL
);

CREATE TABLE config_keys (
    id uuid NOT NULL,
    product_id uuid NOT NULL,
    key text NOT NULL,
    exposure text NOT NULL,
    value_type text DEFAULT 'string'::text NOT NULL,
    status text DEFAULT 'active'::text NOT NULL,
    description text,
    created_at timestamp with time zone NOT NULL,
    updated_at timestamp with time zone NOT NULL,
    created_by_account_id uuid NOT NULL,
    CONSTRAINT config_keys_exposure_check CHECK ((exposure = ANY (ARRAY['public'::text, 'private'::text, 'secret'::text]))),
    CONSTRAINT config_keys_status_check CHECK ((status = ANY (ARRAY['active'::text, 'archived'::text]))),
    CONSTRAINT config_keys_value_type_check CHECK ((value_type = ANY (ARRAY['string'::text, 'int'::text, 'decimal'::text, 'bool'::text, 'string[]'::text, 'int[]'::text, 'decimal[]'::text, 'bool[]'::text, 'json'::text])))
);

CREATE TABLE config_values (
    id uuid NOT NULL,
    product_id uuid NOT NULL,
    app_id uuid NOT NULL,
    config_key_id uuid NOT NULL,
    value_json jsonb,
    value_encrypted bytea,
    updated_at timestamp with time zone NOT NULL,
    updated_by_account_id uuid NOT NULL,
    CONSTRAINT config_values_one_value_check CHECK ((((value_json IS NOT NULL) AND (value_encrypted IS NULL)) OR ((value_json IS NULL) AND (value_encrypted IS NOT NULL))))
);

CREATE TABLE dpop_replay (
    jkt text NOT NULL,
    jti text NOT NULL,
    expires_at timestamp with time zone NOT NULL
);

CREATE TABLE email_change_requests (
    id uuid NOT NULL,
    user_id uuid NOT NULL,
    app_id uuid NOT NULL,
    new_email text NOT NULL,
    code_hash text NOT NULL,
    attempts integer DEFAULT 0 NOT NULL,
    expires_at timestamp with time zone NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);

CREATE TABLE feature_flag_overrides (
    id uuid NOT NULL,
    product_id uuid NOT NULL,
    app_id uuid NOT NULL,
    feature_flag_id uuid NOT NULL,
    enabled boolean DEFAULT false NOT NULL,
    status text DEFAULT 'active'::text NOT NULL,
    role_ids uuid[] DEFAULT '{}'::uuid[],
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_by_account_id uuid NOT NULL
);

CREATE TABLE feature_flags (
    id uuid NOT NULL,
    product_id uuid NOT NULL,
    key text NOT NULL,
    description text,
    scope text DEFAULT 'server'::text NOT NULL,
    default_enabled boolean DEFAULT false NOT NULL,
    status text DEFAULT 'active'::text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    created_by_account_id uuid NOT NULL,
    CONSTRAINT feature_flags_scope_check CHECK ((scope = ANY (ARRAY['server'::text, 'client'::text])))
);

CREATE TABLE magic_links (
    id uuid NOT NULL,
    purpose text NOT NULL,
    email text NOT NULL,
    token_hash text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    expires_at timestamp with time zone NOT NULL,
    used_at timestamp with time zone
);

CREATE TABLE oauth_states (
    jti uuid NOT NULL,
    app_id uuid NOT NULL,
    provider text NOT NULL,
    opener_origin text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    expires_at timestamp with time zone NOT NULL,
    consumed_at timestamp with time zone,
    prelogin_session_id uuid,
    CONSTRAINT oauth_states_provider_check CHECK ((provider = ANY (ARRAY['google'::text, 'apple'::text, 'microsoft'::text, 'github'::text])))
);

CREATE TABLE permissions (
    id uuid NOT NULL,
    product_id uuid NOT NULL,
    name text NOT NULL,
    slug text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);

CREATE TABLE products (
    id uuid NOT NULL,
    workspace_id uuid NOT NULL,
    name text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    created_by_account_id uuid
);

CREATE TABLE role_permissions (
    id uuid NOT NULL,
    role_id uuid NOT NULL,
    permission_id uuid NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);

CREATE TABLE roles (
    id uuid NOT NULL,
    product_id uuid NOT NULL,
    name text NOT NULL,
    slug text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);

CREATE TABLE sessions (
    id uuid NOT NULL,
    account_id uuid NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    expires_at timestamp with time zone NOT NULL,
    last_seen_at timestamp with time zone DEFAULT now() NOT NULL,
    token_id uuid NOT NULL,
    token_secret_hash bytea NOT NULL,
    token_prefix text,
    user_agent text,
    ip text
);

CREATE TABLE system_secrets (
    name text NOT NULL,
    value text NOT NULL,
    generated_at timestamp with time zone DEFAULT now() NOT NULL
);

CREATE TABLE team_invites (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    workspace_id uuid NOT NULL,
    email text NOT NULL,
    invited_by uuid NOT NULL,
    status text DEFAULT 'pending'::text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    accepted_at timestamp with time zone,
    CONSTRAINT team_invites_status_check CHECK ((status = ANY (ARRAY['pending'::text, 'accepted'::text])))
);

CREATE TABLE user_field_values (
    id uuid NOT NULL,
    user_id uuid NOT NULL,
    user_field_id uuid NOT NULL,
    value_json jsonb NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_by uuid NOT NULL
);

CREATE TABLE user_fields (
    id uuid NOT NULL,
    key text NOT NULL,
    value_type text DEFAULT 'string'::text NOT NULL,
    visibility text DEFAULT 'server'::text NOT NULL,
    user_editable boolean DEFAULT false NOT NULL,
    label text DEFAULT ''::text NOT NULL,
    status text DEFAULT 'active'::text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    created_by_account_id uuid NOT NULL,
    user_pool_id uuid NOT NULL,
    CONSTRAINT user_fields_status_check CHECK ((status = ANY (ARRAY['active'::text, 'archived'::text]))),
    CONSTRAINT user_fields_value_type_check CHECK ((value_type = ANY (ARRAY['string'::text, 'bool'::text, 'date'::text]))),
    CONSTRAINT user_fields_visibility_check CHECK ((visibility = ANY (ARRAY['client'::text, 'server'::text])))
);

CREATE TABLE user_identities (
    id uuid NOT NULL,
    user_id uuid NOT NULL,
    user_pool_id uuid NOT NULL,
    provider character varying(20) NOT NULL,
    provider_subject text NOT NULL,
    provider_email text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    last_login_at timestamp with time zone DEFAULT now() NOT NULL
);

CREATE TABLE user_passkeys (
    id uuid NOT NULL,
    app_id uuid NOT NULL,
    user_id uuid NOT NULL,
    credential_id bytea NOT NULL,
    public_key bytea NOT NULL,
    sign_count bigint DEFAULT 0 NOT NULL,
    transports character varying(40)[] DEFAULT '{}'::character varying[] NOT NULL,
    aaguid uuid,
    backup_eligible boolean DEFAULT false NOT NULL,
    backup_state boolean DEFAULT false NOT NULL,
    name character varying(80),
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    last_used_at timestamp with time zone
);

CREATE TABLE user_permissions (
    id uuid NOT NULL,
    app_id uuid NOT NULL,
    user_id uuid NOT NULL,
    permission_id uuid NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);

CREATE TABLE user_pools (
    id uuid NOT NULL,
    workspace_id uuid NOT NULL,
    name text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);

CREATE TABLE user_roles (
    id uuid NOT NULL,
    app_id uuid NOT NULL,
    user_id uuid NOT NULL,
    role_id uuid NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);

CREATE TABLE user_tags (
    id uuid NOT NULL,
    app_id uuid NOT NULL,
    user_id uuid NOT NULL,
    tag character varying(40) NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);

CREATE TABLE users (
    id uuid NOT NULL,
    email text NOT NULL,
    enabled boolean DEFAULT true NOT NULL,
    email_verified_at timestamp with time zone,
    password_hash text,
    password_set_at timestamp with time zone,
    source character varying(20) DEFAULT 'invited'::character varying NOT NULL,
    locked_until timestamp with time zone,
    last_login_at timestamp with time zone,
    totp_secret_encrypted bytea,
    totp_enabled_at timestamp with time zone,
    totp_backup_codes_encrypted bytea,
    last_totp_step bigint DEFAULT 0 NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    user_pool_id uuid NOT NULL
);

CREATE TABLE webauthn_challenges (
    id uuid NOT NULL,
    app_id uuid NOT NULL,
    user_id uuid,
    purpose character varying(20) NOT NULL,
    challenge bytea NOT NULL,
    session_data jsonb NOT NULL,
    expires_at timestamp with time zone NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT webauthn_challenges_purpose_check CHECK (((purpose)::text = ANY ((ARRAY['register'::character varying, 'login'::character varying])::text[])))
);

CREATE TABLE webhook_deliveries (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    webhook_id uuid NOT NULL,
    event text NOT NULL,
    payload jsonb NOT NULL,
    status text DEFAULT 'pending'::text NOT NULL,
    status_code integer,
    response_body text,
    attempts integer DEFAULT 0 NOT NULL,
    next_retry_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    completed_at timestamp with time zone,
    CONSTRAINT webhook_deliveries_status_check CHECK ((status = ANY (ARRAY['pending'::text, 'success'::text, 'failed'::text])))
);

CREATE TABLE webhooks (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    product_id uuid NOT NULL,
    app_id uuid NOT NULL,
    url text NOT NULL,
    secret text NOT NULL,
    events text[] DEFAULT '{}'::text[] NOT NULL,
    status text DEFAULT 'active'::text NOT NULL,
    description text DEFAULT ''::text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    created_by uuid NOT NULL,
    CONSTRAINT webhooks_status_check CHECK ((status = ANY (ARRAY['active'::text, 'disabled'::text])))
);

CREATE TABLE workspace_admins (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    workspace_id uuid NOT NULL,
    account_id uuid NOT NULL,
    role text DEFAULT 'admin'::text NOT NULL,
    added_by uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL
