CREATE TABLE workspace_encryption_keys (
    id uuid NOT NULL,
    workspace_id uuid NOT NULL,
    public_key_jwk jsonb NOT NULL,
    fingerprint text NOT NULL,
    created_at timestamp with time zone NOT NULL,
    created_by uuid
);

CREATE TABLE workspace_smtp_config (
    workspace_id uuid NOT NULL,
    enabled boolean DEFAULT false NOT NULL,
    host text DEFAULT ''::text NOT NULL,
    port integer DEFAULT 587 NOT NULL,
    username text DEFAULT ''::text NOT NULL,
    password_encrypted bytea,
    from_email text DEFAULT ''::text NOT NULL,
    from_name text DEFAULT ''::text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);

CREATE TABLE workspaces (
    id uuid NOT NULL,
    name text NOT NULL,
    slug text NOT NULL,
    status smallint DEFAULT 1 NOT NULL,
    cookie_domain text,
    setup_checklist_dismissed_at timestamp with time zone,
    setup_test_email_sent_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    created_by uuid,
    google_oauth_client_id text
);

